parameters.jsCode:
const webhook = $('Webhook onboarding-client').item.json.body;
const profiles = $('GET profil client').all();
const avocats = $('GET avocat référent').all();

const client = profiles[0]?.json?.[0] ?? {
  id: webhook.profile_id,
  full_name: webhook.client_name,
  email: webhook.client_email,
  company: webhook.client_company,
};

const avocat = avocats[0]?.json?.[0] ?? null;

const now = new Date();
const ref = 'ONBOARDING-' + now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0') + '-' + client.id.substring(0, 8).toUpperCase();

const rdvDate = new Date(now);
rdvDate.setDate(rdvDate.getDate() + 7);
rdvDate.setHours(10, 0, 0, 0);
const rdvEnd = new Date(rdvDate);
rdvEnd.setMinutes(rdvEnd.getMinutes() + 60);

return [{
  json: {
    profile_id: client.id,
    avocat_id: avocat?.id ?? null,
    client_name: client.full_name,
    client_email: client.email,
    client_company: client.company ?? '',
    avocat_name: avocat?.full_name ?? 'votre avocat référent',
    avocat_title: avocat?.title ?? '',
    avocat_email: avocat?.email ?? 'contact@maison-alderic.be',
    dossier_ref: ref,
    dossier_title: 'Consultation initiale — ' + (client.company || client.full_name),
    rdv_starts_at: rdvDate.toISOString(),
    rdv_ends_at: rdvEnd.toISOString(),
    triggered_by: webhook.triggered_by,
    triggered_at: webhook.triggered_at,
  }
}];

